const authData = $input.item.json;
const body = authData.body || {};

// Normalize content_type to DB CHECK constraint values
const rawType = (body.content_type || 'text').toLowerCase().trim();
let contentType = 'text';
if (rawType.includes('video') || rawType.includes('reel')) contentType = 'video';
else if (rawType.includes('carousel') || rawType.includes('thread')) contentType = 'carousel';
else if (rawType.includes('image')) contentType = 'image';
else contentType = 'text';

// Normalize platform to DB CHECK constraint values
const rawPlatform = (body.platform || 'linkedin').toLowerCase().trim();
let platform = 'linkedin';
if (rawPlatform.includes('instagram')) platform = 'instagram';
else if (rawPlatform.includes('x') || rawPlatform.includes('twitter')) platform = 'x';
else if (rawPlatform.includes('youtube')) platform = 'youtube';
else platform = 'linkedin';

return {
  json: {
    user_id: authData.user_id,
    title: body.title || body.theme || 'Untitled Post',
    content: body.content || body.post_text || '',
    content_type: contentType,
    platform: platform,
    scheduled_date: body.scheduled_date || body.scheduled_for || null,
    status: 'pending_review',
    image_url: body.image_url || null,
    video_url: body.video_url || null,
    image_prompt: body.image_prompt || '',
    campaign_id: body.campaign_id || null,
    theme_id: body.theme_id || null
  }
};
